mapper.sql:
FROM daily_quote dq JOIN stock_basic sb ON dq.ts_code = sb.ts_code LEFT JOIN daily_basic db ON dq.ts_code = db.ts_code AND dq.trade_date = db.trade_date LEFT JOIN sw_industry_member sim ON dq.ts_code = sim.ts_code AND sim.is_new = '1' LEFT JOIN sw_industry si ON sim.index_code = si.index_code AND si.level = 1 WHERE dq.trade_date = #{tradeDate} AND sb.list_status = 'L'
AND si.index_code = #{industryCode}
AND dq.ts_code LIKE '%.SH'
AND dq.ts_code LIKE '%.SZ'
AND sb.market = #{market}

mapper.select:
SELECT m.ts_code AS tsCode, b.name AS name, q.close AS close, q.pct_chg AS pctChg, q.vol AS vol, q.amount AS amount, b.market AS market FROM sw_industry_member m INNER JOIN stock_basic b ON m.ts_code = b.ts_code LEFT JOIN daily_quote q ON m.ts_code = q.ts_code AND q.trade_date = #{tradeDate} WHERE m.index_code = #{indexCode} AND m.is_new = '1'
AND (b.name LIKE CONCAT('%', #{keyword}, '%') OR m.ts_code LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY q.pct_chg DESC LIMIT #{size} OFFSET #{offset}
